// src/game/client/world/world.ts
var WorldEvent = {
  ObjectLoaded: 1,
  ObjectPositionChanged: 2,
  PlayerLoaded: 3,
  ClientPlayerPositionChanged: 4,
  ClientConnected: 5
};

class World {
  camera;
  viewport;
  user;
  objects;
  renderer;
  sky;
  listeners;
  requestIds;
  constructor(viewport) {
    this.camera = new Camera(viewport, {
      zoomSpeed: 0.05,
      minZoom: 0.75,
      maxZoom: 2.5,
      padding: 100,
      speed: 0.05,
      peek: 0.01
    });
    this.requestIds = new Set;
    this.listeners = new DefaultMap(() => []);
    this.viewport = viewport;
    this.sky = new Sky;
    this.renderer = new LayeredRenderer;
    const mapBounds = [
      { x: 0, y: 0 },
      { x: WORLD_SIZE, y: WORLD_SIZE }
    ];
    this.objects = new ObjectContainer(mapBounds);
    this.viewport.addChild(this.renderer.container);
    this.viewport.addChild(this.sky);
    this.viewport.sortChildren();
  }
  clear() {
    for (const object of this.objects.all()) {
      this.deleteObjects({ objects: [object.id] });
      this.objects.delete(object.id);
    }
  }
  addEventListener(event, callback) {
    this.listeners.get(event).push(callback);
  }
  removeEventListener(event, callback) {
    this.listeners.set(event, this.listeners.get(event).filter((cb) => cb !== callback));
  }
  emitEvent(event, data) {
    this.listeners.get(event).forEach((cb) => cb(data));
  }
  tick() {
    AnimationManagers.World.update();
    this.objects.update(serverTime.now());
  }
  clientConnectionInfo = (packet) => {
    if (packet) {
      this.user = packet.playerId;
      serverTime.start = packet.serverStartTime;
      console.log(`Server start time: ${serverTime.start}`);
    }
    if (!this.user)
      return;
    const player = this.objects.get(this.user);
    if (!player) {
      console.warn(`No player with id ${this.user} found in world, retrying..`);
      return setTimeout(this.clientConnectionInfo, 500);
    }
    console.info(`Found user (id ${this.user}), loading..`);
    this.camera.target = player.position;
    this.camera.snap();
    console.debug("Snapping camera..");
    this.emitEvent(WorldEvent.ClientConnected, player);
  };
  getUser() {
    return this.objects.get(this.user ?? -1);
  }
  newPlayer = (packet) => {
    const id = packet.id;
    this.renderer.delete(id);
    console.log(`Loading new player with id: ${id}`);
    const pos = new Point(packet.x, packet.y);
    const name = new Text(packet.name, TEXT_STYLE);
    const player = new Player(id, AnimationManagers.World, name, pos, packet.rotation);
    player.setEquipment(packet);
    this.objects.add(player);
    this.renderer.add(player.id, ...player.containers);
    this.emitEvent(WorldEvent.PlayerLoaded, player);
  };
  moveObject = (packet, now) => {
    const id = packet.id;
    const state = { timestamp: now, x: packet.x, y: packet.y };
    const object = this.objects.get(id);
    if (!object) {
      this.requestIds.add(id);
      return;
    }
    if (id === this.user)
      this.emitEvent(WorldEvent.ClientPlayerPositionChanged, state);
    object.renderable = true;
    object.addState(state);
    this.emitEvent(WorldEvent.ObjectPositionChanged, object);
    this.objects.updating.add(object);
    this.objects.add(object);
  };
  rotateObject = (packet, now) => {
    const id = packet.id;
    const state = { timestamp: now, rotation: radians(packet.rotation) };
    if (id === this.user)
      return;
    const object = this.objects.get(id);
    if (!object)
      return this.requestIds.add(id);
    object.addState(state);
    this.objects.updating.add(object);
  };
  deleteObjects = ({ objects }) => {
    for (const id of objects) {
      const object = this.objects.get(id);
      this.objects.delete(id);
      AnimationManagers.World.remove(object);
      this.renderer.delete(id);
    }
  };
  attack = ({ id }) => {
    const object = this.objects.get(id);
    if (!object)
      return;
    object.trigger(300 /* ATTACK */, AnimationManagers.World, true);
  };
  block = ({ id, stop }) => {
    const object = this.objects.get(id);
    if (!object || !(object instanceof Player))
      return;
    if (stop)
      return object.blocking = false;
    object.blocking = true;
    object.trigger(301 /* BLOCK */, AnimationManagers.World);
  };
  hurt = ({ id, angle }) => {
    const object = this.objects.get(id);
    if (!object)
      return;
    object.trigger(100 /* HURT */, AnimationManagers.World, true);
  };
  updateEquipment = (packet) => {
    const player = this.objects.get(packet.id);
    if (player instanceof Player) {
      player.setEquipment(packet);
    }
  };
  selectStructure = (packet) => {
    const player = this.objects.get(this.user || -1);
    if (player instanceof Player) {
      player.setSelectedStructure(packet.structureId, packet.structureSize);
    }
  };
  loadGround = (packet) => {
    for (const data of packet.groundData) {
      const ground = createGround(...data);
      this.renderer.add(-10, ground);
    }
  };
  unloadObject = ({ objects }) => {
    for (const id of objects) {
      const object = this.objects.get(id);
      if (object) {
        object.renderable = false;
      }
    }
  };
  chatMessage = ({ id, message }) => {
    const player = this.objects.get(id);
    if (!player)
      return;
    if (player.name)
      console.log(player.name.text, message);
  };
}

