var inventoryGrid = new Grid(percentOf(10, ITEM_BUTTON_SIZE), percentOf(10, ITEM_BUTTON_SIZE), ITEM_BUTTON_SIZE, ITEM_BUTTON_SIZE, 1);

class Inventory {
  container = new Container;
  buttons = [];
  slots = [];
  items = new Map;
  rightClickCB;
  leftClickCB;
  constructor() {
    this.slotCount = 0;
  }
  set slotCount(count2) {
    const diff = count2 - this.buttons.length;
    if (diff > 0) {
      for (let i2 = 0;i2 < diff; i2++) {
        const button = new InventoryButton;
        button.leftclick = this.leftClickCB;
        button.rightclick = this.rightClickCB;
        button.button.onpointerdown = (ev) => {
          if (ev?.button === 2)
            button.rightDown = true;
          button.down = true;
        };
        this.buttons.push(button);
        this.container.addChild(button.button);
        this.slots.push(null);
      }
    }
    if (diff < 0) {
      for (let i2 = 0;i2 < -diff; i2++) {
        const btn = this.buttons.pop();
        if (btn)
          this.container.removeChild(btn.button);
        btn?.destroy();
        this.slots.pop();
      }
    }
    inventoryGrid.arrange(this.buttons);
  }
  get slotCount() {
    return this.buttons.length;
  }
  set leftclick(value) {
    this.leftClickCB = value;
    this.buttons.forEach((b2) => b2.leftclick = value);
  }
  set rightclick(value) {
    this.rightClickCB = value;
    this.buttons.forEach((b2) => b2.rightclick = value);
  }
  update({ items }) {
    this.slotCount = items.length;
    this.slots = Array(this.slotCount).fill(null);
    this.items.clear();
    for (const [i2, stack] of items.entries()) {
      if (stack) {
        const [id, amount] = stack;
        const itemCount = this.items.get(id) ?? 0;
        this.items.set(id, itemCount + amount);
      }
      this.slots[i2] = stack;
    }
    for (const [i2, button] of this.buttons.entries()) {
      button.clear();
      const item = this.slots[i2];
      if (!item)
        continue;
      const [itemId, amount] = item;
      button.amount.text = prettifyNumber(amount);
      button.item = itemId;
    }
    this.resize();
  }
  resize() {
    this.container.position.set(percentOf(50, window.innerWidth) - percentOf(50, (ITEM_BUTTON_SIZE + percentOf(10, ITEM_BUTTON_SIZE)) * (this.slotCount - 1)), window.innerHeight - ITEM_BUTTON_SIZE / 2 - percentOf(10, ITEM_BUTTON_SIZE));
  }
}

