// src/game/client/ui/ui.ts
function createUI() {
  const ui = new Container;
  const inventory = new Inventory;
  const recipeManager = new RecipeManager;
  const craftingGrid = new Grid(percentOf(10, ITEM_BUTTON_SIZE), percentOf(10, ITEM_BUTTON_SIZE), ITEM_BUTTON_SIZE, ITEM_BUTTON_SIZE, 3);
  const craftingMenu = new CraftingMenu(craftingGrid);
  const swordTimer = new Timer("sword_timer");
  const statsGrid = new Grid(60, 5, 150, 60, 1);
  const health = new StatBar({
    max: 200,
    icon: "health_bar_icon",
    tint: 8976983,
    overlayTint: 3648920,
    diffTint: 13959140,
    warnOnHigh: false,
    split: false
  });
  const hunger = new StatBar({
    max: 100,
    split: false,
    icon: "hunger_bar_icon",
    tint: 11561776,
    overlayTint: 13927511,
    diffTint: 7231048,
    warnOnHigh: false
  });
  const heat = new StatBar({
    max: 200,
    split: true,
    icon: "heat_bar_icon",
    tint: 12081736,
    overlayTint: 11545130,
    diffTint: 6257541
  });
  const statContainer = new Container;
  statContainer.pivot.set(statContainer.width / 2, statContainer.height / 2);
  statContainer.addChild(health.container);
  statContainer.addChild(hunger.container);
  statContainer.addChild(heat.container);
  statsGrid.arrange([health.container, hunger.container, heat.container]);
  function resize() {
    craftingMenu.resize();
    inventory.resize();
    statContainer.position.set(percentOf(50, window.innerWidth) - percentOf(46, (150 + 60) * 3), inventory.container.position.y - ITEM_BUTTON_SIZE - statsGrid.spacingV);
    swordTimer.container.position.set(100, percentOf(75, window.innerHeight));
  }
  window.addEventListener("resize", resize);
  ui.addChild(statContainer);
  ui.addChild(inventory.container);
  ui.addChild(swordTimer.container);
  ui.addChild(craftingMenu.container);
  return {
    container: ui,
    inventory,
    craftingMenu,
    recipeManager,
    swordTimer,
    health,
    hunger,
    heat
  };
}

